function excluir_ProdDestino_Promocao(id) {

  Swal.fire({
    title: 'Certeza que Deseja Excluir esse Produto da Promoção?',
    text: "Você não poderá reverter esta ação!",
    buttonsStyling: false,
    showCancelButton: true,
    customClass: {
      confirmButton: 'btn btn-primary btn-lg',
      cancelButton: 'btn btn-danger btn-lg',
      loader: 'custom-loader'
    },
    loaderHtml: '<div class="spinner-border text-primary"></div>',
    preConfirm: () => {
      Swal.showLoading()
      return new Promise((resolve) => {

        ajaxPut('api/compras/delete_produtosdestinopromocoes.xsjs?IDDetalheProdDestino=' + id)
          .then(funcSucessDelProdDestPromocao)
          .catch(funcError);

      })
    }
  })
}

